#include <stdio.h>
#include <stdlib.h>

typedef long long ll;

static ll *bit;
static int N;

void bit_init(int n) {
    N = n + 2;
    bit = (ll*)calloc(N + 1, sizeof(ll));
}

void bit_add(int idx, ll val) {
    for (int i = idx; i <= N; i += i & -i) bit[i] += val;
}

ll bit_sum(int idx) {
    ll res = 0;
    for (int i = idx; i > 0; i -= i & -i) res += bit[i];
    return res;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int n, m; ll c; scanf("%d %d %lld", &n, &m, &c);
        bit_init(n+2);
        for (int i = 0; i < m; ++i) {
            char type; scanf(" %c", &type);
            if (type == 'S') {
                int u, v; ll k; scanf("%d %d %lld", &u, &v, &k);
                bit_add(u, k);
                if (v + 1 <= n) bit_add(v + 1, -k);
            } else if (type == 'Q') {
                int p; scanf("%d", &p);
                ll ans = c + bit_sum(p);
                printf("%lld\n", ans);
            }
        }
        free(bit);
    }
    return 0;
}

