using ll = long long;

struct Fenwick {
    int n; vector<ll> bit;
    Fenwick(int n=0){init(n);}    
    void init(int n_){n=n_; bit.assign(n+2,0);}    
    void add(int idx, ll val){ for(int i=idx;i<=n;i+=i&-i) bit[i]+=val; }
    ll sum(int idx) const{ ll s=0; for(int i=idx;i>0;i-=i&-i) s+=bit[i]; return s; }
};

