import java.io.*;
import java.util.*;

public class Main {
    static class Fenwick {
        int n; long[] bit;
        Fenwick(int n){ this.n=n; bit=new long[n+2]; }
        void add(int idx, long val){ for(int i=idx;i<=n;i+=i&-i) bit[i]+=val; }
        long sum(int idx){ long s=0; for(int i=idx;i>0;i-=i&-i) s+=bit[i]; return s; }
    }
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder out = new StringBuilder();
        while(T-- > 0){
            int n = fs.nextInt();
            int m = fs.nextInt();
            long c = fs.nextLong();
            Fenwick ft = new Fenwick(n+2);
            for(int i=0;i<m;++i){
                char type = fs.next().charAt(0);
                if(type=='S'){
                    int u = fs.nextInt();
                    int v = fs.nextInt();
                    long k = fs.nextLong();
                    ft.add(u,k);
                    if(v+1<=n) ft.add(v+1,-k);
                }else{ // Q
                    int p = fs.nextInt();
                    long ans = c + ft.sum(p);
                    out.append(ans).append('\n');
                }
            }
        }
        System.out.print(out.toString());
    }
    // Fast scanner
    static class FastScanner {
        private final BufferedInputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream is){ in = new BufferedInputStream(is); }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        String next() throws IOException {
            StringBuilder sb = new StringBuilder();
            int c;
            while ((c = readByte()) != -1 && c <= ' ') {}
            while (c != -1 && c > ' ') {
                sb.append((char) c);
                c = readByte();
            }
            return sb.toString();
        }
        int nextInt() throws IOException { return Integer.parseInt(next()); }
        long nextLong() throws IOException { return Long.parseLong(next()); }
    }
}

