import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        n = int(next(it)); m = int(next(it)); c = int(next(it))
        size = n + 2
        bit = [0] * (size + 1)
        def bit_add(idx, val):
            while idx <= size:
                bit[idx] += val
                idx += idx & -idx
        def bit_sum(idx):
            s = 0
            while idx > 0:
                s += bit[idx]
                idx -= idx & -idx
            return s
        for __ in range(m):
            typ = next(it)
            if typ == 'S':
                u = int(next(it)); v = int(next(it)); k = int(next(it))
                bit_add(u, k)
                if v + 1 <= n:
                    bit_add(v + 1, -k)
            else:  # Q
                p = int(next(it))
                ans = c + bit_sum(p)
                out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

